program lipdecide;

{$mode objfpc}
{$H+}

uses
  Math, SysUtils;

const
  PI = 3.1415926535;

type
  POINTRANGE = 1..100;
  LICRANGE = 1..15;
  NPOINTS = 2..100;
  NPTYPE = 3..100;
  CONNECTORS = (NOTUSED, ORR, ANDD);
  NUMQUADS = 1..3;
  COORDINATE = array[POINTRANGE] of real;
  CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX = array[LICRANGE, LICRANGE] of boolean;
  VECTOR = array[LICRANGE] of boolean;
  COMPTYPE = (LT, EQ, GT);

  PARAMETERSREC = record
    LENGTH1: real;
    RADIUS1: real;
    EPSILON: real;
    AREA1: real;
    Q_PTS: NPOINTS;
    QUADS: NUMQUADS;
    DIST: real;
    N_PTS: NPTYPE;
    K_PTS: POINTRANGE;
    A_PTS: POINTRANGE;
    B_PTS: POINTRANGE;
    C_PTS: POINTRANGE;
    D_PTS: POINTRANGE;
    E_PTS: POINTRANGE;
    F_PTS: POINTRANGE;
    G_PTS: POINTRANGE;
    LENGTH2: real;
    RADIUS2: real;
    AREA2: real;
  end;

var
  X: COORDINATE;
  Y: COORDINATE;
  NUMPOINTS: NPOINTS;
  PARAMETERS: PARAMETERSREC;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

  InputText: AnsiString;
  InputPos: LongInt;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

procedure Fail;
begin
  Halt(1);
end;

procedure SkipWhitespace;
begin
  while (InputPos <= Length(InputText)) and (InputText[InputPos] in [' ', #9, #10, #13]) do
    Inc(InputPos);
end;

function PeekChar: Char;
begin
  SkipWhitespace;
  if InputPos > Length(InputText) then
    PeekChar := #0
  else
    PeekChar := InputText[InputPos];
end;

procedure ExpectChar(C: Char);
begin
  SkipWhitespace;
  if (InputPos > Length(InputText)) or (InputText[InputPos] <> C) then
    Fail;
  Inc(InputPos);
end;

function ParseString: AnsiString;
var
  Ch: Char;
begin
  SkipWhitespace;
  if (InputPos > Length(InputText)) or (InputText[InputPos] <> '"') then
    Fail;
  Inc(InputPos);
  ParseString := '';
  while InputPos <= Length(InputText) do
  begin
    Ch := InputText[InputPos];
    Inc(InputPos);
    if Ch = '"' then
      Exit;
    if Ch = '\' then
    begin
      if InputPos > Length(InputText) then
        Fail;
      Ch := InputText[InputPos];
      Inc(InputPos);
      case Ch of
        '"', '\', '/': ParseString := ParseString + Ch;
        'b': ParseString := ParseString + #8;
        'f': ParseString := ParseString + #12;
        'n': ParseString := ParseString + #10;
        'r': ParseString := ParseString + #13;
        't': ParseString := ParseString + #9;
      else
        Fail;
      end;
    end
    else
      ParseString := ParseString + Ch;
  end;
  Fail;
end;

function ParseBoolean: boolean;
begin
  SkipWhitespace;
  if Copy(InputText, InputPos, 4) = 'true' then
  begin
    Inc(InputPos, 4);
    ParseBoolean := True;
  end
  else if Copy(InputText, InputPos, 5) = 'false' then
  begin
    Inc(InputPos, 5);
    ParseBoolean := False;
  end
  else
    Fail;
end;

function ParseNumberToken: AnsiString;
begin
  SkipWhitespace;
  ParseNumberToken := '';
  while (InputPos <= Length(InputText)) and (InputText[InputPos] in ['0'..'9', '-', '+', '.', 'e', 'E']) do
  begin
    ParseNumberToken := ParseNumberToken + InputText[InputPos];
    Inc(InputPos);
  end;
  if ParseNumberToken = '' then
    Fail;
end;

function ParseInteger: LongInt;
var
  Token: AnsiString;
  Code: Integer;
begin
  Token := ParseNumberToken;
  Val(Token, ParseInteger, Code);
  if Code <> 0 then
    Fail;
end;

function ParseReal: real;
var
  Token: AnsiString;
  Code: Integer;
begin
  Token := ParseNumberToken;
  Val(Token, ParseReal, Code);
  if Code <> 0 then
    Fail;
end;

procedure ParseCoordinateArray(var Arr: COORDINATE; var CountOut: Integer);
begin
  CountOut := 0;
  ExpectChar('[');
  SkipWhitespace;
  if PeekChar = ']' then
  begin
    ExpectChar(']');
    Exit;
  end;
  while True do
  begin
    Inc(CountOut);
    Arr[CountOut] := ParseReal;
    SkipWhitespace;
    if PeekChar = ']' then
    begin
      ExpectChar(']');
      Break;
    end;
    ExpectChar(',');
  end;
end;

function ParseConnectorValue: CONNECTORS;
var
  S: AnsiString;
begin
  S := ParseString;
  if S = 'NOTUSED' then
    ParseConnectorValue := NOTUSED
  else if S = 'ORR' then
    ParseConnectorValue := ORR
  else if S = 'ANDD' then
    ParseConnectorValue := ANDD
  else
    Fail;
end;

procedure ParseLCM;
var
  I, J: Integer;
begin
  ExpectChar('[');
  for I := 1 to 15 do
  begin
    ExpectChar('[');
    for J := 1 to 15 do
    begin
      LCM[I, J] := ParseConnectorValue;
      if J < 15 then
        ExpectChar(',');
    end;
    ExpectChar(']');
    if I < 15 then
      ExpectChar(',');
  end;
  ExpectChar(']');
end;

procedure ParsePUMDiag;
var
  I, J: Integer;
begin
  for I := 1 to 15 do
    for J := 1 to 15 do
      PUM[I, J] := False;

  ExpectChar('[');
  for I := 1 to 15 do
  begin
    PUM[I, I] := ParseBoolean;
    if I < 15 then
      ExpectChar(',');
  end;
  ExpectChar(']');
end;

procedure ParseParameters;
var
  Key: AnsiString;
begin
  ExpectChar('{');
  while True do
  begin
    Key := ParseString;
    ExpectChar(':');
    if Key = 'LENGTH1' then
      PARAMETERS.LENGTH1 := ParseReal
    else if Key = 'RADIUS1' then
      PARAMETERS.RADIUS1 := ParseReal
    else if Key = 'EPSILON' then
      PARAMETERS.EPSILON := ParseReal
    else if Key = 'AREA1' then
      PARAMETERS.AREA1 := ParseReal
    else if Key = 'Q_PTS' then
      PARAMETERS.Q_PTS := ParseInteger
    else if Key = 'QUADS' then
      PARAMETERS.QUADS := ParseInteger
    else if Key = 'DIST' then
      PARAMETERS.DIST := ParseReal
    else if Key = 'N_PTS' then
      PARAMETERS.N_PTS := ParseInteger
    else if Key = 'K_PTS' then
      PARAMETERS.K_PTS := ParseInteger
    else if Key = 'A_PTS' then
      PARAMETERS.A_PTS := ParseInteger
    else if Key = 'B_PTS' then
      PARAMETERS.B_PTS := ParseInteger
    else if Key = 'C_PTS' then
      PARAMETERS.C_PTS := ParseInteger
    else if Key = 'D_PTS' then
      PARAMETERS.D_PTS := ParseInteger
    else if Key = 'E_PTS' then
      PARAMETERS.E_PTS := ParseInteger
    else if Key = 'F_PTS' then
      PARAMETERS.F_PTS := ParseInteger
    else if Key = 'G_PTS' then
      PARAMETERS.G_PTS := ParseInteger
    else if Key = 'LENGTH2' then
      PARAMETERS.LENGTH2 := ParseReal
    else if Key = 'RADIUS2' then
      PARAMETERS.RADIUS2 := ParseReal
    else if Key = 'AREA2' then
      PARAMETERS.AREA2 := ParseReal
    else
      Fail;

    SkipWhitespace;
    if PeekChar = '}' then
    begin
      ExpectChar('}');
      Break;
    end;
    ExpectChar(',');
  end;
end;

procedure ParseInput;
var
  Key: AnsiString;
  XCount, YCount: Integer;
begin
  XCount := 0;
  YCount := 0;
  ExpectChar('{');
  while True do
  begin
    Key := ParseString;
    ExpectChar(':');
    if Key = 'numpoints' then
      NUMPOINTS := ParseInteger
    else if Key = 'x' then
      ParseCoordinateArray(X, XCount)
    else if Key = 'y' then
      ParseCoordinateArray(Y, YCount)
    else if Key = 'parameters' then
      ParseParameters
    else if Key = 'lcm' then
      ParseLCM
    else if Key = 'pum_diag' then
      ParsePUMDiag
    else
      Fail;

    SkipWhitespace;
    if PeekChar = '}' then
    begin
      ExpectChar('}');
      Break;
    end;
    ExpectChar(',');
  end;

  if (XCount <> NUMPOINTS) or (YCount <> NUMPOINTS) then
    Fail;
end;

function DistanceBetween(I, J: Integer): real;
var
  DX, DY: real;
begin
  DX := X[J] - X[I];
  DY := Y[J] - Y[I];
  DistanceBetween := Sqrt(DX * DX + DY * DY);
end;

function TriangleArea(I, J, K: Integer): real;
var
  Cross: real;
begin
  Cross := (X[J] - X[I]) * (Y[K] - Y[I]) - (Y[J] - Y[I]) * (X[K] - X[I]);
  TriangleArea := Abs(Cross) / 2.0;
end;

function PointsCoincide(I, J: Integer): boolean;
begin
  PointsCoincide := (REALCOMPARE(X[I], X[J]) = EQ) and (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function AngleAtVertex(I, J, K: Integer; var Defined: boolean): real;
var
  V1X, V1Y, V2X, V2Y: real;
  Len1, Len2, CosineValue: real;
begin
  V1X := X[I] - X[J];
  V1Y := Y[I] - Y[J];
  V2X := X[K] - X[J];
  V2Y := Y[K] - Y[J];
  Len1 := Sqrt(V1X * V1X + V1Y * V1Y);
  Len2 := Sqrt(V2X * V2X + V2Y * V2Y);
  if (REALCOMPARE(Len1, 0.0) = EQ) or (REALCOMPARE(Len2, 0.0) = EQ) then
  begin
    Defined := False;
    AngleAtVertex := 0.0;
    Exit;
  end;

  CosineValue := (V1X * V2X + V1Y * V2Y) / (Len1 * Len2);
  if REALCOMPARE(CosineValue, 1.0) = GT then
    CosineValue := 1.0
  else if REALCOMPARE(CosineValue, -1.0) = LT then
    CosineValue := -1.0;

  Defined := True;
  AngleAtVertex := ArcCos(CosineValue);
end;

function QuadrantOfPoint(I: Integer): Integer;
var
  XCmp, YCmp: COMPTYPE;
begin
  XCmp := REALCOMPARE(X[I], 0.0);
  YCmp := REALCOMPARE(Y[I], 0.0);
  if (XCmp <> LT) and (YCmp <> LT) then
    QuadrantOfPoint := 1
  else if (XCmp = LT) and (YCmp <> LT) then
    QuadrantOfPoint := 2
  else if (XCmp <> GT) and (YCmp = LT) then
    QuadrantOfPoint := 3
  else
    QuadrantOfPoint := 4;
end;

function DistancePointToLine(PointIdx, StartIdx, EndIdx: Integer): real;
var
  Numerator, Denominator: real;
begin
  if PointsCoincide(StartIdx, EndIdx) then
  begin
    DistancePointToLine := DistanceBetween(PointIdx, StartIdx);
    Exit;
  end;

  Numerator := Abs((Y[EndIdx] - Y[StartIdx]) * X[PointIdx] -
                   (X[EndIdx] - X[StartIdx]) * Y[PointIdx] +
                   X[EndIdx] * Y[StartIdx] - Y[EndIdx] * X[StartIdx]);
  Denominator := DistanceBetween(StartIdx, EndIdx);
  DistancePointToLine := Numerator / Denominator;
end;

function CanContainWithinCircle(I, J, K: Integer; Radius: real): boolean;
var
  A, B, C, MaxSide, Side1, Side2, AreaValue, CircumRadius: real;
  MaxSq, OthersSq: real;
begin
  A := DistanceBetween(I, J);
  B := DistanceBetween(J, K);
  C := DistanceBetween(I, K);

  MaxSide := A;
  Side1 := B;
  Side2 := C;
  if REALCOMPARE(B, MaxSide) = GT then
  begin
    MaxSide := B;
    Side1 := A;
    Side2 := C;
  end;
  if REALCOMPARE(C, MaxSide) = GT then
  begin
    MaxSide := C;
    Side1 := A;
    Side2 := B;
  end;

  if REALCOMPARE(MaxSide, 2.0 * Radius) = GT then
  begin
    CanContainWithinCircle := False;
    Exit;
  end;

  MaxSq := MaxSide * MaxSide;
  OthersSq := Side1 * Side1 + Side2 * Side2;
  if REALCOMPARE(MaxSq, OthersSq) <> LT then
  begin
    CanContainWithinCircle := True;
    Exit;
  end;

  AreaValue := TriangleArea(I, J, K);
  if REALCOMPARE(AreaValue, 0.0) = EQ then
  begin
    CanContainWithinCircle := True;
    Exit;
  end;

  CircumRadius := (A * B * C) / (4.0 * AreaValue);
  CanContainWithinCircle := REALCOMPARE(CircumRadius, Radius) <> GT;
end;

function EvaluateLIC1: boolean;
var
  I: Integer;
begin
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(DistanceBetween(I, I + 1), PARAMETERS.LENGTH1) = GT then
    begin
      EvaluateLIC1 := True;
      Exit;
    end;
  EvaluateLIC1 := False;
end;

function EvaluateLIC2: boolean;
var
  I: Integer;
begin
  for I := 1 to NUMPOINTS - 2 do
    if not CanContainWithinCircle(I, I + 1, I + 2, PARAMETERS.RADIUS1) then
    begin
      EvaluateLIC2 := True;
      Exit;
    end;
  EvaluateLIC2 := False;
end;

function EvaluateLIC3: boolean;
var
  I: Integer;
  AngleValue: real;
  Defined: boolean;
begin
  for I := 1 to NUMPOINTS - 2 do
  begin
    AngleValue := AngleAtVertex(I, I + 1, I + 2, Defined);
    if Defined and
       ((REALCOMPARE(AngleValue, PI - PARAMETERS.EPSILON) = LT) or
        (REALCOMPARE(AngleValue, PI + PARAMETERS.EPSILON) = GT)) then
    begin
      EvaluateLIC3 := True;
      Exit;
    end;
  end;
  EvaluateLIC3 := False;
end;

function EvaluateLIC4: boolean;
var
  I: Integer;
begin
  for I := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(I, I + 1, I + 2), PARAMETERS.AREA1) = GT then
    begin
      EvaluateLIC4 := True;
      Exit;
    end;
  EvaluateLIC4 := False;
end;

function EvaluateLIC5: boolean;
var
  I, J, QuadCount: Integer;
  Seen: array[1..4] of boolean;
begin
  for I := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for J := 1 to 4 do
      Seen[J] := False;
    QuadCount := 0;
    for J := I to I + PARAMETERS.Q_PTS - 1 do
      if not Seen[QuadrantOfPoint(J)] then
      begin
        Seen[QuadrantOfPoint(J)] := True;
        Inc(QuadCount);
      end;
    if QuadCount > PARAMETERS.QUADS then
    begin
      EvaluateLIC5 := True;
      Exit;
    end;
  end;
  EvaluateLIC5 := False;
end;

function EvaluateLIC6: boolean;
var
  I: Integer;
begin
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[I + 1] - X[I], 0.0) = LT then
    begin
      EvaluateLIC6 := True;
      Exit;
    end;
  EvaluateLIC6 := False;
end;

function EvaluateLIC7: boolean;
var
  StartIdx, EndIdx, MidIdx: Integer;
begin
  if NUMPOINTS < 3 then
  begin
    EvaluateLIC7 := False;
    Exit;
  end;

  for StartIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    EndIdx := StartIdx + PARAMETERS.N_PTS - 1;
    for MidIdx := StartIdx + 1 to EndIdx - 1 do
      if REALCOMPARE(DistancePointToLine(MidIdx, StartIdx, EndIdx), PARAMETERS.DIST) = GT then
      begin
        EvaluateLIC7 := True;
        Exit;
      end;
  end;
  EvaluateLIC7 := False;
end;

function EvaluateLIC8: boolean;
var
  I, J: Integer;
begin
  if NUMPOINTS < 3 then
  begin
    EvaluateLIC8 := False;
    Exit;
  end;

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(DistanceBetween(I, J), PARAMETERS.LENGTH1) = GT then
    begin
      EvaluateLIC8 := True;
      Exit;
    end;
  end;
  EvaluateLIC8 := False;
end;

function EvaluateLIC9: boolean;
var
  I, J, K: Integer;
begin
  if NUMPOINTS < 5 then
  begin
    EvaluateLIC9 := False;
    Exit;
  end;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if not CanContainWithinCircle(I, J, K, PARAMETERS.RADIUS1) then
    begin
      EvaluateLIC9 := True;
      Exit;
    end;
  end;
  EvaluateLIC9 := False;
end;

function EvaluateLIC10: boolean;
var
  I, J, K: Integer;
  AngleValue: real;
  Defined: boolean;
begin
  if NUMPOINTS < 5 then
  begin
    EvaluateLIC10 := False;
    Exit;
  end;

  for I := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    J := I + PARAMETERS.C_PTS + 1;
    K := J + PARAMETERS.D_PTS + 1;
    AngleValue := AngleAtVertex(I, J, K, Defined);
    if Defined and
       ((REALCOMPARE(AngleValue, PI - PARAMETERS.EPSILON) = LT) or
        (REALCOMPARE(AngleValue, PI + PARAMETERS.EPSILON) = GT)) then
    begin
      EvaluateLIC10 := True;
      Exit;
    end;
  end;
  EvaluateLIC10 := False;
end;

function EvaluateLIC11: boolean;
var
  I, J, K: Integer;
begin
  if NUMPOINTS < 5 then
  begin
    EvaluateLIC11 := False;
    Exit;
  end;

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    if REALCOMPARE(TriangleArea(I, J, K), PARAMETERS.AREA1) = GT then
    begin
      EvaluateLIC11 := True;
      Exit;
    end;
  end;
  EvaluateLIC11 := False;
end;

function EvaluateLIC12: boolean;
var
  I, J: Integer;
begin
  if NUMPOINTS < 3 then
  begin
    EvaluateLIC12 := False;
    Exit;
  end;

  for I := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    J := I + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[J] - X[I], 0.0) = LT then
    begin
      EvaluateLIC12 := True;
      Exit;
    end;
  end;
  EvaluateLIC12 := False;
end;

function EvaluateLIC13: boolean;
var
  I, J: Integer;
  FoundLong, FoundShort: boolean;
  DistValue: real;
begin
  if NUMPOINTS < 3 then
  begin
    EvaluateLIC13 := False;
    Exit;
  end;

  FoundLong := False;
  FoundShort := False;
  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    DistValue := DistanceBetween(I, J);
    if REALCOMPARE(DistValue, PARAMETERS.LENGTH1) = GT then
      FoundLong := True;
    if REALCOMPARE(DistValue, PARAMETERS.LENGTH2) = LT then
      FoundShort := True;
  end;
  EvaluateLIC13 := FoundLong and FoundShort;
end;

function EvaluateLIC14: boolean;
var
  I, J, K: Integer;
  FoundOutside, FoundInside: boolean;
begin
  if NUMPOINTS < 5 then
  begin
    EvaluateLIC14 := False;
    Exit;
  end;

  FoundOutside := False;
  FoundInside := False;
  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if not CanContainWithinCircle(I, J, K, PARAMETERS.RADIUS1) then
      FoundOutside := True;
    if CanContainWithinCircle(I, J, K, PARAMETERS.RADIUS2) then
      FoundInside := True;
  end;
  EvaluateLIC14 := FoundOutside and FoundInside;
end;

function EvaluateLIC15: boolean;
var
  I, J, K: Integer;
  AreaValue: real;
  FoundLarge, FoundSmall: boolean;
begin
  if NUMPOINTS < 5 then
  begin
    EvaluateLIC15 := False;
    Exit;
  end;

  FoundLarge := False;
  FoundSmall := False;
  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    AreaValue := TriangleArea(I, J, K);
    if REALCOMPARE(AreaValue, PARAMETERS.AREA1) = GT then
      FoundLarge := True;
    if REALCOMPARE(AreaValue, PARAMETERS.AREA2) = LT then
      FoundSmall := True;
  end;
  EvaluateLIC15 := FoundLarge and FoundSmall;
end;

procedure DECIDE;
var
  I, J: Integer;
  AllTrue: boolean;
begin
  CMV[1] := EvaluateLIC1;
  CMV[2] := EvaluateLIC2;
  CMV[3] := EvaluateLIC3;
  CMV[4] := EvaluateLIC4;
  CMV[5] := EvaluateLIC5;
  CMV[6] := EvaluateLIC6;
  CMV[7] := EvaluateLIC7;
  CMV[8] := EvaluateLIC8;
  CMV[9] := EvaluateLIC9;
  CMV[10] := EvaluateLIC10;
  CMV[11] := EvaluateLIC11;
  CMV[12] := EvaluateLIC12;
  CMV[13] := EvaluateLIC13;
  CMV[14] := EvaluateLIC14;
  CMV[15] := EvaluateLIC15;

  for I := 1 to 15 do
    for J := 1 to 15 do
      if I <> J then
        case LCM[I, J] of
          NOTUSED: PUM[I, J] := True;
          ORR: PUM[I, J] := CMV[I] or CMV[J];
          ANDD: PUM[I, J] := CMV[I] and CMV[J];
        end;

  for I := 1 to 15 do
  begin
    if not PUM[I, I] then
      FUV[I] := True
    else
    begin
      AllTrue := True;
      for J := 1 to 15 do
        if not PUM[I, J] then
        begin
          AllTrue := False;
          Break;
        end;
      FUV[I] := AllTrue;
    end;
  end;

  LAUNCH := True;
  for I := 1 to 15 do
    if not FUV[I] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

procedure WriteBoolean(Value: boolean);
begin
  if Value then
    Write('true')
  else
    Write('false');
end;

procedure WriteBooleanVector(const Values: VECTOR);
var
  I: Integer;
begin
  Write('[');
  for I := 1 to 15 do
  begin
    if I > 1 then
      Write(',');
    WriteBoolean(Values[I]);
  end;
  Write(']');
end;

procedure WritePUMMatrix;
var
  I, J: Integer;
begin
  Write('[');
  for I := 1 to 15 do
  begin
    if I > 1 then
      Write(',');
    Write('[');
    for J := 1 to 15 do
    begin
      if J > 1 then
        Write(',');
      WriteBoolean(PUM[I, J]);
    end;
    Write(']');
  end;
  Write(']');
end;

procedure WriteOutput;
begin
  Write('{');
  Write('"cmv":');
  WriteBooleanVector(CMV);
  Write(',"pum":');
  WritePUMMatrix;
  Write(',"fuv":');
  WriteBooleanVector(FUV);
  Write(',"launch":');
  WriteBoolean(LAUNCH);
  Write('}');
end;

procedure ReadInputText;
var
  Ch: Char;
begin
  InputText := '';
  while not EOF(Input) do
  begin
    Read(Input, Ch);
    InputText := InputText + Ch;
  end;
  InputPos := 1;
end;

begin
  ReadInputText;
  ParseInput;
  DECIDE;
  WriteOutput;
end.
